+func TestSessionAgentRegistryPersistence(t *testing.T) {
+	// Use temp directory for testing
+	tmpDir := t.TempDir()
+	t.Setenv("XDG_CONFIG_HOME", tmpDir)
+
+	sessionName := "test-persist-session"
+	projectKey := filepath.Join(tmpDir, "project")
